import{c as i,Q as a,j as n,m as p}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"微前端模式:模块联邦、沙箱、路由隔离与组织边界","description":"","frontmatter":{},"headers":[],"relativePath":"designPatternLearning/45-微前端模式.md","filePath":"designPatternLearning/45-微前端模式.md","lastUpdated":1779015580000}'),t={name:"designPatternLearning/45-微前端模式.md"};function l(e,s,h,k,r,d){return a(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="微前端模式-模块联邦、沙箱、路由隔离与组织边界" tabindex="-1">微前端模式:模块联邦、沙箱、路由隔离与组织边界 <a class="header-anchor" href="#微前端模式-模块联邦、沙箱、路由隔离与组织边界" aria-label="Permalink to &quot;微前端模式:模块联邦、沙箱、路由隔离与组织边界&quot;">​</a></h1><p>微前端最容易被误解成技术时髦词.很多团队一听&quot;前端太大&quot;,第一反应就是拆微前端.结果原来只是一个仓库难维护,拆完变成十个应用一起难维护,还多了构建、发布、样式冲突、依赖版本和运行时通信问题.</p><p>微前端首先不是技术模式,而是<strong>组织边界在前端运行时的投影</strong>.</p><hr><h2 id="一、问题-大前端应用为什么会撑爆" tabindex="-1">一、问题:大前端应用为什么会撑爆 <a class="header-anchor" href="#一、问题-大前端应用为什么会撑爆" aria-label="Permalink to &quot;一、问题:大前端应用为什么会撑爆&quot;">​</a></h2><p>单体前端会在这些情况下变痛:</p><ul><li>多个业务团队共用一个仓库,发布互相等待.</li><li>一个团队改营销页,另一个团队改交易页,却要一起回归.</li><li>技术栈升级困难,任何依赖变化都影响全站.</li><li>权限、菜单、路由越来越多,应用启动变慢.</li><li>不同业务域的代码互相 import,边界消失.</li></ul><p>稳定点是&quot;用户看到的是一个产品&quot;,变化点是&quot;不同业务团队、发布节奏、技术栈和生命周期不同&quot;.</p><p>微前端试图把变化点隔离:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Shell / Host</span></span>
<span class="line"><span>  -&gt; 登录态、全局导航、布局、公共能力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Remote / Micro App</span></span>
<span class="line"><span>  -&gt; 独立业务域</span></span>
<span class="line"><span>  -&gt; 独立构建</span></span>
<span class="line"><span>  -&gt; 独立发布</span></span>
<span class="line"><span>  -&gt; 受控接入 Shell</span></span></code></pre></div><hr><h2 id="二、常见模式" tabindex="-1">二、常见模式 <a class="header-anchor" href="#二、常见模式" aria-label="Permalink to &quot;二、常见模式&quot;">​</a></h2><p><strong>模式一:构建时集成</strong></p><p>多个包在构建时组合成一个应用,常见于 monorepo:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>packages/</span></span>
<span class="line"><span>  shell/</span></span>
<span class="line"><span>  order/</span></span>
<span class="line"><span>  user/</span></span>
<span class="line"><span>  shared-ui/</span></span></code></pre></div><p>优点是运行时简单,类型和依赖容易检查.缺点是发布仍然可能绑定.</p><p><strong>模式二:运行时集成</strong></p><p>Shell 在运行时加载远程应用:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> OrderApp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> lazy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;order/App&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> AppRoutes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Route</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/orders/*&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> element</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">={&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">OrderApp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;} /&gt;;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>模块联邦就是这类方案的典型实现.优点是独立部署能力强,缺点是运行时失败模式更多.</p><p><strong>模式三:iframe 隔离</strong></p><p>iframe 隔离最强,样式、脚本、全局变量天然分开.缺点是体验和通信成本高,路由、弹窗、埋点、登录态都要额外处理.</p><hr><h2 id="三、关键边界-路由、沙箱、依赖和通信" tabindex="-1">三、关键边界:路由、沙箱、依赖和通信 <a class="header-anchor" href="#三、关键边界-路由、沙箱、依赖和通信" aria-label="Permalink to &quot;三、关键边界:路由、沙箱、依赖和通信&quot;">​</a></h2><p>微前端落地要先定四个边界.</p><p><strong>路由边界</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/orders/*  -&gt; Order App</span></span>
<span class="line"><span>/users/*   -&gt; User App</span></span>
<span class="line"><span>/billing/* -&gt; Billing App</span></span></code></pre></div><p>每个子应用只管理自己的子路由,不要抢全局路由.</p><p><strong>沙箱边界</strong></p><p>要防止子应用污染全局:</p><ul><li>CSS 命名冲突.</li><li>window 全局变量.</li><li>事件监听不卸载.</li><li>定时器不清理.</li></ul><p><strong>依赖边界</strong></p><p>共享依赖不是越多越好.React、路由库、设计系统可以共享,业务工具不要随便共享,否则又会形成隐形单体.</p><p><strong>通信边界</strong></p><p>优先用明确协议:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ShellBridge</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  getAccessToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Promise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  navigate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">path</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  emit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">event</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;cart:changed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">payload</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">count</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> })</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre></div><p>不要让子应用直接 import Shell 内部模块.</p><hr><h2 id="四、落地判断" tabindex="-1">四、落地判断 <a class="header-anchor" href="#四、落地判断" aria-label="Permalink to &quot;四、落地判断&quot;">​</a></h2><p>适合微前端的信号:</p><ul><li>至少两个以上独立团队长期并行开发.</li><li>业务域边界清楚,例如订单、会员、财务.</li><li>发布节奏确实不同,且互相等待成本高.</li><li>已经有稳定的设计系统、登录态、监控、发布平台.</li><li>团队能承担运行时治理成本.</li></ul><p>不适合的信号:</p><ul><li>只是代码目录乱.</li><li>只是构建慢,但团队和发布边界没有分裂.</li><li>只是想让不同页面用不同框架.</li><li>公共能力还没稳定,Shell 自己都经常变.</li><li>没有自动化测试和灰度发布能力.</li></ul><p>很多时候,先做 monorepo、模块边界、路由懒加载、包拆分,就能解决 70% 的问题.</p><hr><h2 id="五、代价与误用" tabindex="-1">五、代价与误用 <a class="header-anchor" href="#五、代价与误用" aria-label="Permalink to &quot;五、代价与误用&quot;">​</a></h2><p>微前端引入的是分布式系统问题:</p><ul><li>远程资源加载失败怎么办.</li><li>Host 和 Remote 版本不兼容怎么办.</li><li>共享依赖重复加载怎么办.</li><li>子应用样式污染怎么办.</li><li>跨应用跳转和埋点怎么统一.</li><li>本地开发怎么同时启动多个应用.</li></ul><p>常见误用:</p><p><strong>误用一:用微前端替代模块化</strong>.模块边界都没想清楚,运行时拆分只会放大混乱.</p><p><strong>误用二:共享包变成新的单体核心</strong>.所有业务都依赖 <code>shared-business</code>,最后改共享包比改单体还难.</p><p><strong>误用三:通信变成全局 EventBus</strong>.事件名没人管,数据结构没人管,调用链不可追踪.</p><p><strong>误用四:忽略用户体验</strong>.子应用加载慢、样式跳动、错误页不统一,用户不会关心你是不是微前端.</p><hr><h2 id="六、一句话总结" tabindex="-1">六、一句话总结 <a class="header-anchor" href="#六、一句话总结" aria-label="Permalink to &quot;六、一句话总结&quot;">​</a></h2><blockquote><p><strong>微前端解决的是组织和发布边界,不是目录整理问题</strong>.只有当团队、业务域和发布节奏真的需要隔离时,模块联邦、沙箱和路由隔离才值得付出成本.</p></blockquote>`,56)])])}const c=i(t,[["render",l]]);export{g as __pageData,c as default};
